import OpenAI from 'openai';
import { VexClient } from 'vex-sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

export async function handleRunCompleted(event: any) {
  const { threadId, runId } = event.data.object;

  const run = await openai.beta.threads.runs.retrieve(threadId, runId);
  const messages = await openai.beta.threads.messages.list(threadId);

  const contextCheck = await vex.verify({
    policy: 'education-thread-limits',
    input: { messageCount: messages.data.length, runId },
    metadata: { usage: run.usage?.total_tokens }
  });

  if (!contextCheck.passed && run.usage!.total_tokens > 100000) {
    await openai.beta.threads.messages.create(threadId, {
      role: 'assistant',
      content: '[CONTEXT LIMIT REACHED: Start new conversation for compliance]'
    });
  }

  return contextCheck;
}
